class Solution {
public:
    vector<int> findClosestElements(vector<int>& a, int k, int x) {
        int lo=0, hi=a.size()-k;
        while(lo<hi){
            int mid=(lo+hi)/2;
            if(x-a[mid]>a[mid+k]-x) lo=mid+1; else hi=mid;
        }
        return vector<int>(a.begin()+lo,a.begin()+lo+k);
    }
};
